/// Reduced scale for Catmull-Rom arithmetic: 10^6.
///
/// All Catmull-Rom intermediates stay in i64. The worst-case product is
/// ~25e6 × 10^6 = 2.5e13, well within i64 max (9.2e18).
const S6: i64 = 1_000_000;
/// Shift factor: SCALE / S6 = 10^6.
const SHIFT: i64 = 1_000_000;

/// Catmull-Rom cubic in pure i64 at SCALE_6.
///
/// p0..p3 at SCALE_6, t ∈ [0, S6]. Returns interpolated value at SCALE_6.
/// No i128 arithmetic anywhere.
#[inline]
fn catmull_rom_i64(p0: i64, p1: i64, p2: i64, p3: i64, t: i64) -> i64 {
    let a = -p0 + 3 * p1 - 3 * p2 + p3;
    let b = 2 * p0 - 5 * p1 + 4 * p2 - p3;
    let c = -p0 + p2;
    let d = 2 * p1;

    // Horner: ((a*t/S6 + b)*t/S6 + c)*t/S6 + d, then /2
    let val = a;
    let val = val * t / S6 + b;
    let val = val * t / S6 + c;
    let val = val * t / S6 + d;
    val / 2
}

/// Look up a table value with clamped index, downshifted to SCALE_6.
#[inline]
fn table_get_s6(table: &[[i64; N]; N], i: i32, j: i32) -> i64 {
    let i = i.clamp(0, N as i32 - 1) as usize;
    let j = j.clamp(0, N as i32 - 1) as usize;
    table[i][j] / SHIFT
}

/// Bicubic (Catmull-Rom) interpolation of the C table — pure i64 path.
///
/// `a` and `b` are signed fixed-point at SCALE (i128), clamped to [-4, 4].
/// Returns C(a,b) at SCALE as i128.
///
/// Internally everything runs in i64 at SCALE_6. The only i128 usage is
/// the input conversion and the final upshift.
#[inline]
fn bicubic_eval(table: &[[i64; N]; N], a: i128, b: i128) -> i128 {
    let a_c = a.clamp(DOMAIN_MIN, DOMAIN_MAX) as i64;
    let b_c = b.clamp(DOMAIN_MIN, DOMAIN_MAX) as i64;

    let domain_min = DOMAIN_MIN as i64;
    let range = (DOMAIN_MAX - DOMAIN_MIN) as i64; // 8e12

    // Index computation in i64: a_off * 63 fits (max 8e12 * 63 = 5e14 < 9.2e18)
    let a_off = a_c - domain_min;
    let b_off = b_c - domain_min;

    let ia_scaled = a_off * (N as i64 - 1);
    let i0 = (ia_scaled / range) as i32;
    // Fractional part at SCALE_6: (rem * S6) / range. Max rem = 8e12, * 1e6 = 8e18 < 9.2e18.
    let frac_a = ((ia_scaled % range) * S6 / range) as i64;

    let ib_scaled = b_off * (N as i64 - 1);
    let j0 = (ib_scaled / range) as i32;
    let frac_b = ((ib_scaled % range) * S6 / range) as i64;

    let i0 = i0.min(N as i32 - 2);
    let j0 = j0.min(N as i32 - 2);

    // Inner: 4 Catmull-Rom evals over b, each producing an i64 at SCALE_6
    let mut col_vals = [0i64; 4];
    for di in 0..4i32 {
        let ii = i0 - 1 + di;
        let p0 = table_get_s6(table, ii, j0 - 1);
        let p1 = table_get_s6(table, ii, j0);
        let p2 = table_get_s6(table, ii, j0 + 1);
        let p3 = table_get_s6(table, ii, j0 + 2);
        col_vals[di as usize] = catmull_rom_i64(p0, p1, p2, p3, frac_b);
    }

    // Outer: Catmull-Rom over a, result at SCALE_6
    let result_s6 = catmull_rom_i64(col_vals[0], col_vals[1], col_vals[2], col_vals[3], frac_a);

    // Upshift to SCALE
    result_s6 as i128 * SHIFT as i128
}

/// Fast bivariate normal CDF via const C-table with bicubic interpolation.
///
/// Computes `P(X <= a, Y <= b)` where `(X, Y)` is standard bivariate normal
/// with correlation `rho`.
///
/// # Arguments
///
/// * `a`, `b` — signed fixed-point at SCALE, clamped to [-4, 4].
/// * `table` — the precomputed C-table for this ρ (use `CTABLE_*` constants).
///
/// # Accuracy
///
/// Max absolute error < 4e-5 across [-4,4]² (validated on 300×300 grid and
/// 10,000 random points against scipy).
///
/// # CU cost
///
/// Measured on localnet, not estimated.
///
/// # Errors
///
/// - `Overflow` from `norm_cdf_poly` or `fp_mul_i` (extremely unlikely in domain).
pub fn bvn_cdf_ctable(a: i128, b: i128, table: &[[i64; N]; N]) -> Result<i128, SolMathError> {
    let a_c = a.clamp(DOMAIN_MIN, DOMAIN_MAX);
    let b_c = b.clamp(DOMAIN_MIN, DOMAIN_MAX);

    // 1. Independence baseline: Φ(a) · Φ(b)
    let phi_a = norm_cdf_poly(a_c)?;
    let phi_b = norm_cdf_poly(b_c)?;
    let baseline = fp_mul_i(phi_a, phi_b)?;

    // 2. Correction from table
    let correction = bicubic_eval(table, a_c, b_c);

    // 3. Assemble
    let result = baseline
        .checked_add(correction)
        .ok_or(SolMathError::Overflow)?;

    Ok(result.clamp(0, SCALE_I))
}

#[cfg(test)]
mod tests {
    extern crate std;
    use std::vec::Vec;

    use super::*;
    use crate::bvn_cdf::bvn_cdf;

    fn phi_f64(x: f64) -> f64 {
        0.398_942_280_401_432_7 * (-0.5 * x * x).exp()
    }

    fn std_norm_cdf_ref(x: f64) -> f64 {
        if x < -10.0 {
            return 0.0;
        }
        if x > 10.0 {
            return 1.0;
        }
        let n = 4_096usize;
        let left = -10.0f64;
        let h = (x - left) / n as f64;
        let mut sum = phi_f64(left) + phi_f64(x);
        for i in 1..n {
            let xi = left + h * i as f64;
            sum += if i % 2 == 0 {
                2.0 * phi_f64(xi)
            } else {
                4.0 * phi_f64(xi)
            };
        }
        (sum * h / 3.0).clamp(0.0, 1.0)
    }

    fn bvn_cdf_ref(x: f64, y: f64, rho: f64) -> f64 {
        if rho >= 0.999_999 {
            return std_norm_cdf_ref(x.min(y));
        }
        if rho <= -0.999_999 {
            return (std_norm_cdf_ref(x) + std_norm_cdf_ref(y) - 1.0).clamp(0.0, 1.0);
        }
        if x > 0.0 && y > 0.0 {
            return (std_norm_cdf_ref(x) + std_norm_cdf_ref(y) - 1.0 + bvn_cdf_ref(-x, -y, rho))
                .clamp(0.0, 1.0);
        }
        if x > 0.0 {
            return (std_norm_cdf_ref(y) - bvn_cdf_ref(-x, y, -rho)).clamp(0.0, 1.0);
        }
        if y > 0.0 {
            return (std_norm_cdf_ref(x) - bvn_cdf_ref(x, -y, -rho)).clamp(0.0, 1.0);
        }
        let alpha = rho.asin();
        let base = std_norm_cdf_ref(x) * std_norm_cdf_ref(y);
        let n = 4_096usize;
        let h = alpha / n as f64;
        let mut sum = 1.0
            + (-(x * x - 2.0 * x * y * (alpha.sin()) + y * y) / (2.0 * (alpha.cos()).powi(2)))
                .exp();
        for i in 1..n {
            let theta = h * i as f64;
            let exponent =
                -(x * x - 2.0 * x * y * theta.sin() + y * y) / (2.0 * theta.cos().powi(2));
            sum += if i % 2 == 0 {
                2.0 * exponent.exp()
            } else {
                4.0 * exponent.exp()
            };
        }
        (base + sum * h / 3.0 / (2.0 * core::f64::consts::PI)).clamp(0.0, 1.0)
    }

    fn test_ctable_vs_f64(table: &[[i64; N]; N], rho_f64: f64, label: &str) {
        let mut state = 0x1234_5678_9abc_def0u64;
        let mut max_err = 0.0f64;
        for _ in 0..2_048 {
            state = state
                .wrapping_mul(6_364_136_223_846_793_005)
                .wrapping_add(1);
            let x = (((state >> 11) % 8_001) as i64 - 4_000) as f64 / 1_000.0;
            state = state
                .wrapping_mul(6_364_136_223_846_793_005)
                .wrapping_add(1);
            let y = (((state >> 9) % 8_001) as i64 - 4_000) as f64 / 1_000.0;

            let a_fp = (x * SCALE_I as f64).round() as i128;
            let b_fp = (y * SCALE_I as f64).round() as i128;
            let fast = bvn_cdf_ctable(a_fp, b_fp, table).expect("ctable") as f64 / SCALE_I as f64;
            let want = bvn_cdf_ref(x, y, rho_f64);
            let err = (fast - want).abs();
            if err > max_err {
                max_err = err;
            }
        }
        assert!(
            max_err < 1.0e-4,
            "{label}: max_err={max_err:.2e} (target < 1e-4)"
        );
    }

    #[test]
    fn ctable_iwm_qqq_vs_f64() {
        test_ctable_vs_f64(&CTABLE_IWM_QQQ, 0.7763218317079643, "IWM_QQQ");
    }

    #[test]
    fn ctable_iwm_spy_vs_f64() {
        test_ctable_vs_f64(&CTABLE_IWM_SPY, 0.8635323683789009, "IWM_SPY");
    }

    #[test]
    fn ctable_qqq_spy_vs_f64() {
        test_ctable_vs_f64(&CTABLE_QQQ_SPY, 0.8989418379506557, "QQQ_SPY");
    }

    #[test]
    fn ctable_symmetry() {
        let pts = [-3.0, -1.5, 0.0, 1.5, 3.0];
        for table in [&CTABLE_IWM_QQQ, &CTABLE_QQQ_SPY] {
            for &x in &pts {
                for &y in &pts {
                    let a = (x * SCALE_I as f64).round() as i128;
                    let b = (y * SCALE_I as f64).round() as i128;
                    let v_ab = bvn_cdf_ctable(a, b, table).expect("ab");
                    let v_ba = bvn_cdf_ctable(b, a, table).expect("ba");
                    assert!(
                        (v_ab - v_ba).abs() < 100_000_000,
                        "symmetry: diff={}",
                        (v_ab - v_ba).abs()
                    );
                }
            }
        }
    }

    #[test]
    fn ctable_boundary_values() {
        for table in [&CTABLE_IWM_QQQ, &CTABLE_IWM_SPY, &CTABLE_QQQ_SPY] {
            let v = bvn_cdf_ctable(-4 * SCALE_I, -4 * SCALE_I, table).expect("lo");
            assert!(v >= 0 && v < SCALE_I / 100);
            let v = bvn_cdf_ctable(4 * SCALE_I, 4 * SCALE_I, table).expect("hi");
            assert!(v > SCALE_I * 99 / 100 && v <= SCALE_I);
        }
    }
}
